typedef struct Node{int data;struct Node*next;}Node;

Node* mk(int v){Node*n=malloc(sizeof(Node));n->data=v;n->next=NULL;return n;}

void print(Node*h){
    while(h){printf("%d->",h->data);h=h->next;}
    printf("NULL\n");
}

int main(){
    Node *h=mk(1);
    h->next=mk(2);
    h->next->next=mk(3);
    print(h); // 1->2->3->NULL
}

